.tab-btn {
  background:none; border:none; color:rgba(255,255,255,.5);
  padding:11px 16px; cursor:pointer; font-size:.85rem;
  font-family:inherit; white-space:nowrap;
  border-bottom:3px solid transparent;
  transition:color .2s,border-color .2s;
}
.tab-btn:hover  { color:rgba(255,255,255,.85); }
.tab-btn.active { color:#fff; border-bottom-color:var(--accent); }

/* ── Layout ────────────────────────────────────────────────── */
.workspace {
  display:grid; grid-template-columns:330px 1fr;
  height:calc(100vh - 115px);
}
.sidebar {
  background:#fff; border-right:1px solid #dde3ec;
  overflow-y:auto; padding:16px 14px;
}
.results-panel { background:var(--light); overflow-y:auto; padding:18px 20px; }

/* ── Sidebar form ──────────────────────────────────────────── */
.sec-title {
  font-size:.72rem; font-weight:700; text-transform:uppercase;
  letter-spacing:.06em; color:var(--blue);
  border-bottom:1px solid #ccd6e0; padding-bottom:4px; margin-bottom:8px;
}
.form-sec { margin-bottom:16px; }
.field-row { display:flex; align-items:center; gap:6px; margin-bottom:6px; }
.field-row label { flex:1; font-size:.82rem; color:#334; line-height:1.2; }
.field-row label small { display:block; font-size:.7rem; color:#888; }
.field-row input,.field-row select {
  width:115px; flex-shrink:0; font-size:.82rem;
  padding:4px 7px; border:1px solid #c8d0da; border-radius:5px;
  background:#f8fafc; font-family:inherit;
}
.field-row input:focus,.field-row select:focus {
  outline:none; border-color:var(--accent); background:#fff;
}
.btn-calc {
  width:100%; background:var(--blue); color:#fff; border:none;
  border-radius:7px; padding:10px; font-size:.95rem;
  font-family:inherit; cursor:pointer; font-weight:700;
  margin-top:6px; transition:background .2s;
}
.btn-calc:hover  { background:var(--accent); }
.btn-find {
  width:100%; background:#fff; color:var(--blue);
  border:1.5px solid var(--blue); border-radius:7px; padding:8px;
  font-size:.85rem; font-family:inherit; cursor:pointer; font-weight:600;
  margin-top:5px; transition:background .2s,color .2s;
}
.btn-find:hover { background:var(--blue); color:#fff; }

/* ── Results panel toolbar ─────────────────────────────────── */
.results-toolbar {
  display:flex; align-items:center; justify-content:space-between;
  margin-bottom:14px;
}
.results-toolbar h2 { margin:0; font-size:1rem; color:var(--blue); font-weight:700; }

