async function calculate(mod) {
  const btn = document.getElementById('btn-'+mod);
  btn.innerHTML = '<span class="spinner"></span>กำลังคำนวณ...';
  btn.disabled = true;
  try {
    const res  = await fetch(API, { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({module:mod, inputs:collectInputs(mod)}) });
    const data = await res.json();
    if (data.error) showError(data.error);
    else { _lastModule=mod; _lastData=data; renderResults(mod,data); }
  } catch(e) {
    showError('เชื่อมต่อ API ไม่ได้: '+e.message);
  } finally {
    btn.innerHTML = 'คำนวณ (Calculate)';
    btn.disabled = false;
  }
}

