/* ─────────────────────────────────────────────────────────────────────────
   Render results
───────────────────────────────────────────────────────────────────────── */
function renderResults(mod, data) {
  document.getElementById('placeholder').style.display = 'none';
  document.getElementById('btn-pdf').style.display = '';

