/* ─────────────────────────────────────────────────────────────────────────
   Export PDF
───────────────────────────────────────────────────────────────────────── */
function exportPDF() {
  // Expand all collapsed sections before printing
  document.querySelectorAll('#rpt-body').forEach(el=>el.style.display='');
  document.querySelectorAll('.collapsible').forEach(el=>el.classList.add('open'));
  window.print();
}

/* ─────────────────────────────────────────────────────────────────────────
   Misc helpers
───────────────────────────────────────────────────────────────────────── */
function showContent(html) {
  document.getElementById('placeholder').style.display = 'none';
  const el = document.getElementById('results-content');
  el.style.display = 'block';
  el.innerHTML = html;
}
function showPlaceholder() {
  document.getElementById('placeholder').style.display = '';
  const el = document.getElementById('results-content');
  el.style.display = 'none'; el.innerHTML = '';
  document.getElementById('btn-pdf').style.display = 'none';
}
function showError(msg) {
  showContent(`<div class="rcard" style="border-left:4px solid var(--fail)">
    <h3 style="color:var(--fail)">เกิดข้อผิดพลาด</h3>
    <pre style="font-size:.82rem;margin:0;font-family:'Fira Mono',monospace;white-space:pre-wrap">${esc(msg)}</pre>
  </div>`);
}
function toggleReport(el) {
  const body = document.getElementById('rpt-body');
  const open = body.style.display !== 'none';

